import{_ as i,o as l,c as e,Q as p}from"./chunks/framework.2275ac6f.js";const f=JSON.parse('{"title":"人物描写-形容词","description":"","frontmatter":{"title":"人物描写-形容词","date":"2021-03-15T10:41:53.000Z","tags":["英语","大学","笔记"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":2,"title":"《隐秘的角落》","slug":"《隐秘的角落》","link":"#《隐秘的角落》","children":[{"level":3,"title":"张东升","slug":"张东升","link":"#张东升","children":[]},{"level":3,"title":"朱朝阳","slug":"朱朝阳","link":"#朱朝阳","children":[]},{"level":3,"title":"普普","slug":"普普","link":"#普普","children":[]},{"level":3,"title":"严良","slug":"严良","link":"#严良","children":[]}]},{"level":2,"title":"UNKNOWN TV SERIES","slug":"unknown-tv-series","link":"#unknown-tv-series","children":[{"level":3,"title":"SOME STRANGE ROLES","slug":"some-strange-roles","link":"#some-strange-roles","children":[]}]},{"level":2,"title":"EXPANSION (CET4)","slug":"expansion-cet4","link":"#expansion-cet4","children":[]}],"relativePath":"src/杂项/人物描写-形容词.md","lastUpdated":1718000534000}'),a={name:"src/杂项/人物描写-形容词.md"},t=p('<blockquote><p>Happiness is the meaning and the purpose of life, the whole aim and the end of human existance.<div style="text-align:right;">—— Aristotle</div></p></blockquote><h2 id="《隐秘的角落》" tabindex="-1">《隐秘的角落》 <a class="header-anchor" href="#《隐秘的角落》" aria-hidden="true">#</a></h2><h3 id="张东升" tabindex="-1">张东升 <a class="header-anchor" href="#张东升" aria-hidden="true">#</a></h3><ul><li><p>terrifying 可怕的</p></li><li><p>creepy 令人毛骨悚然的</p></li><li><p>hypocritical 虚伪的，伪善的</p></li><li><p>merciless 无情的</p></li><li><p>chilly 冷淡，冷漠的 阴冷的，寒冷的</p></li></ul><h3 id="朱朝阳" tabindex="-1">朱朝阳 <a class="header-anchor" href="#朱朝阳" aria-hidden="true">#</a></h3><ul><li><p>self-contradictory 自相矛盾的</p></li><li><p>gloomy 阴暗悲观的 忧郁沮丧的</p></li><li><p>lonely 孤单的</p></li><li><p>scheming 心机的</p></li><li><p>evil 邪恶的</p></li></ul><h3 id="普普" tabindex="-1">普普 <a class="header-anchor" href="#普普" aria-hidden="true">#</a></h3><ul><li><p>innocent 天真无辜的</p></li><li><p>pure 单纯的</p></li><li><p>thoughtful 周到的</p></li><li><p>fragile 脆弱的</p></li><li><p>kind-hearted 善良的</p></li></ul><h3 id="严良" tabindex="-1">严良 <a class="header-anchor" href="#严良" aria-hidden="true">#</a></h3><ul><li><p>straightforward 直截了当的</p></li><li><p>gallant 英勇的</p></li><li><p>simple-minded 头脑简单的</p></li><li><p>faithful 真诚的</p></li><li><p>conscientious 有良心的</p></li></ul><h2 id="unknown-tv-series" tabindex="-1">UNKNOWN TV SERIES <a class="header-anchor" href="#unknown-tv-series" aria-hidden="true">#</a></h2><h3 id="some-strange-roles" tabindex="-1">SOME STRANGE ROLES <a class="header-anchor" href="#some-strange-roles" aria-hidden="true">#</a></h3><ul><li><p>open-minded 开明的</p></li><li><p>compassionate 富有同情心的</p></li><li><p>loving 有爱的</p></li><li><p>lovable 讨喜的</p></li><li><p>amiable 和蔼的，不摆架子的</p></li><li><p>good-tempered 好脾气的</p></li><li><p>sophisticated 老练的，见多识广的 水平高的，在行的</p></li><li><p>stubborn 固执的</p></li><li><p>subjective 客观的</p></li><li><p>shrewd 精明的</p></li><li><p>taciturn 沉默寡言的</p></li><li><p>stressful 紧张的</p></li><li><p>responsible 富有责任心的</p></li><li><p>blue 忧郁的</p></li><li><p>resilient 元气满满的 （给人感觉就是满血复活那样）</p></li><li><p>generous 慷慨大方的</p></li><li><p>capable 能干的</p></li><li><p>perfectionistic 追求完美的</p></li><li><p>strong-willed 意志坚强的</p></li><li><p>well-educated 受过良好教育的</p></li></ul><h2 id="expansion-cet4" tabindex="-1">EXPANSION (CET4) <a class="header-anchor" href="#expansion-cet4" aria-hidden="true">#</a></h2><ul><li><p>maverick 特立独行的</p></li><li><p>independent 独立的</p></li><li><p>career-oriented 以职业为导向的</p></li><li><p>ambitious 有志向的</p></li><li><p>persistent 执着不屈的</p></li><li><p>ordinary 普通的</p></li><li><p>peaceful 和平的</p></li><li><p>emotional 感性的</p></li><li><p>childish 幼稚，孩子气的</p></li><li><p>introspective 内省的（反思自己）</p></li><li><p>arrogant 傲慢自大的</p></li><li><p>clumsy 笨拙的</p></li><li><p>bold 莽撞的</p></li><li><p>casual 随意的，漫不经心的</p></li><li><p>cautious 谨慎的(褒义词) 谨小慎微的(贬义词)</p></li><li><p>energetic 精力充沛的</p></li><li><p>eloquent 雄辩的(比如律师)</p></li><li><p>frank 直率的</p></li><li><p>greedy 贪婪的</p></li><li><p>hostile 怀有敌意的，敌对的</p></li><li><p>mechanical 机车的(e.g:你这人真的很机车欸！) 死板的</p></li><li><p>moody 喜怒无常的</p></li><li><p>radical 激进的，极端的</p></li><li><p>passive 被动的</p></li><li><p>enthusiastic 热情的</p></li><li><p>rational 理智的</p></li></ul>',15),n=[t];function r(s,d,o,h,c,u){return l(),e("div",null,n)}const g=i(a,[["render",r]]);export{f as __pageData,g as default};
